changeSet.sql:
ALTER TABLE fixed_operational_costs ADD COLUMN IF NOT EXISTS cost_date timestamp without time zone NOT NULL DEFAULT now();
ALTER TABLE fixed_capital_costs ADD COLUMN IF NOT EXISTS cost_date timestamp without time zone NOT NULL DEFAULT now();
ALTER TABLE variable_costs ADD COLUMN IF NOT EXISTS cost_date timestamp without time zone NOT NULL DEFAULT now();

CREATE INDEX i_fixed_operational_costs_cost_date ON fixed_operational_costs (cost_date);
CREATE INDEX i_fixed_capital_costs_cost_date ON fixed_capital_costs (cost_date);
CREATE INDEX i_variable_costs_cost_date ON variable_costs (cost_date);
